(()=>{'use strict';
const $=s=>document.querySelector(s);
let box,bar,pct,title,detail,stage,active=false,timer=null,started=0,last=0;
function css(){if($('#uploadProgressStyle'))return;const st=document.createElement('style');st.id='uploadProgressStyle';st.textContent=`.upg{position:fixed;left:50%;bottom:14px;transform:translateX(-50%);width:min(94vw,520px);background:#fff;border:1px solid #d1d5db;border-radius:16px;box-shadow:0 14px 44px #0f172a38;z-index:120;overflow:hidden;display:none}.upg.on{display:block}.upgTop{padding:12px 14px 8px;display:flex;justify-content:space-between;gap:10px;align-items:flex-start}.upgTitle{font-weight:950;color:#111827}.upgPct{font-weight:950;color:#087b34;font-size:20px}.upgDetail{padding:0 14px 10px;color:#4b5563;font-size:12px;line-height:1.45}.upgTrack{height:9px;background:#e5e7eb;margin:0 14px 10px;border-radius:999px;overflow:hidden}.upgBar{height:100%;width:0%;background:linear-gradient(90deg,#087b34,#22c55e);transition:width .18s linear}.upgStage{display:grid;grid-template-columns:repeat(4,1fr);gap:0;border-top:1px solid #eef2f7;background:#f8fafc}.upgStage div{font-size:11px;text-align:center;padding:7px 4px;color:#6b7280;font-weight:800}.upgStage div.on{color:#087b34;background:#ecfdf5}.upgErr .upgBar{background:#dc2626}.upgErr .upgPct{color:#dc2626}@media(max-width:420px){.upg{bottom:8px}.upgStage{grid-template-columns:1fr 1fr}.upgPct{font-size:18px}}`;document.head.appendChild(st)}
function ui(){css();if(box)return;box=document.createElement('div');box.className='upg';box.innerHTML='<div class="upgTop"><div class="upgTitle">กำลังเตรียมไฟล์</div><div class="upgPct">0%</div></div><div class="upgDetail">รอเลือกไฟล์</div><div class="upgTrack"><div class="upgBar"></div></div><div class="upgStage"><div data-s="read">อ่านไฟล์</div><div data-s="parse">แปลงข้อมูล</div><div data-s="calc">คำนวณ</div><div data-s="done">เสร็จ</div></div>';document.body.appendChild(box);bar=box.querySelector('.upgBar');pct=box.querySelector('.upgPct');title=box.querySelector('.upgTitle');detail=box.querySelector('.upgDetail');stage=box.querySelector('.upgStage')}
function set(p,t,d,s){ui();last=Math.max(last,Math.min(100,Math.round(p)));bar.style.width=last+'%';pct.textContent=last+'%';if(t)title.textContent=t;if(d)detail.textContent=d;if(s){stage.querySelectorAll('div').forEach(x=>x.classList.toggle('on',x.dataset.s===s))}}
function open(){ui();box.classList.add('on');box.classList.remove('upgErr');active=true;started=Date.now();last=0;set(0,'กำลังเตรียมไฟล์','เริ่มอ่านไฟล์จากเครื่อง','read')}
function closeSoon(){clearInterval(timer);set(100,'อ่านไฟล์สำเร็จ','ข้อมูลแสดงในตารางแล้ว','done');setTimeout(()=>{if(box)box.classList.remove('on');active=false},1600)}
function fail(msg){clearInterval(timer);ui();box.classList.add('upgErr','on');set(Math.max(last,100),'อ่านไฟล์ไม่สำเร็จ',msg||'เกิดข้อผิดพลาด','done');setTimeout(()=>box.classList.remove('on'),3500)}
function fakeParse(){clearInterval(timer);timer=setInterval(()=>{if(!active)return clearInterval(timer);const elapsed=Date.now()-started;let target=last;if(elapsed<1200)target=Math.max(target,60);else if(elapsed<2600)target=Math.max(target,78);else if(elapsed<5200)target=Math.max(target,88);else target=Math.max(target,94);if(last<target)set(last+1,last<72?'กำลังแปลงข้อมูล':'กำลังคำนวณและรวมยอด',last<72?'ตรวจ sheet / pivot / column สำคัญ':'รวม SKU, ร้าน, Telesale และคงเหลือ',last<72?'parse':'calc')},140)}
function readWithProgress(file){return new Promise(resolve=>{try{const r=new FileReader();r.onprogress=e=>{if(!e.lengthComputable)return;const p=5+(e.loaded/e.total)*45;set(p,'กำลังอ่านไฟล์',`${file.name} · ${Math.round(e.loaded/1024).toLocaleString('th-TH')} / ${Math.round(e.total/1024).toLocaleString('th-TH')} KB`,'read')};r.onload=()=>{set(55,'อ่านไฟล์เสร็จ','กำลังส่งให้ระบบแปลงข้อมูล','parse');resolve()};r.onerror=()=>{fail('อ่านไฟล์จากเครื่องไม่สำเร็จ');resolve()};r.readAsArrayBuffer(file)}catch{resolve()}})}
function bind(){ui();const file=$('#file');if(file&&!file.dataset.upgBound){file.dataset.upgBound='1';file.addEventListener('change',async e=>{const f=e.target.files&&e.target.files[0];if(!f)return;open();set(3,'เลือกไฟล์แล้ว',`${f.name} · ${(f.size/1024/1024).toFixed(2)} MB`,'read');await readWithProgress(f);fakeParse()},true)}const msg=$('#msg');if(msg&&!msg.dataset.upgObs){msg.dataset.upgObs='1';new MutationObserver(()=>{const s=(msg.textContent||'').trim();if(!active)return;if(/อ่านสำเร็จ|พร้อมใช้งาน|กู้คืน Autosave/.test(s)){closeSoon()}else if(/ผิดพลาด|ไม่พบข้อมูล|โหลดไม่สำเร็จ|error/i.test(s)){fail(s)}}).observe(msg,{childList:true,subtree:true,characterData:true})}}
document.addEventListener('DOMContentLoaded',()=>{bind();setTimeout(bind,500);new MutationObserver(()=>setTimeout(bind,0)).observe(document.documentElement,{childList:true,subtree:true})});
})();